import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"Failure Alerts","description":"","frontmatter":{},"headers":[],"relativePath":"features/failure-alerts.md","filePath":"features/failure-alerts.md"}'),o={name:"features/failure-alerts.md"};function n(s,e,l,d,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="failure-alerts" tabindex="-1">Failure Alerts <a class="header-anchor" href="#failure-alerts" aria-label="Permalink to &quot;Failure Alerts&quot;">​</a></h1><p>SendGrail can notify you immediately when an email fails to send, allowing you to respond to delivery issues before they affect your users.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When an email delivery attempt fails, SendGrail sends a notification email to the configured alert recipient with details about the failure.</p><h3 id="notification-contents" tabindex="-1">Notification Contents <a class="header-anchor" href="#notification-contents" aria-label="Permalink to &quot;Notification Contents&quot;">​</a></h3><p>Each failure alert includes:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Error Message</strong></td><td>The specific error returned by the SMTP server or transport layer</td></tr><tr><td><strong>Recipient</strong></td><td>The intended recipient of the failed email</td></tr><tr><td><strong>Subject</strong></td><td>The subject line of the failed email</td></tr><tr><td><strong>Timestamp</strong></td><td>When the failure occurred</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Failure alerts are managed through the following settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>notify_on_failure</code></td><td><code>true</code></td><td>Enable or disable failure notifications</td></tr><tr><td><code>notification_email</code></td><td>Site admin email</td><td>The email address that receives failure alerts</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Consider using a shared team inbox or an external monitoring address for failure alerts. This ensures delivery issues are noticed even if the primary admin is unavailable.</p></div><h2 id="loop-prevention" tabindex="-1">Loop Prevention <a class="header-anchor" href="#loop-prevention" aria-label="Permalink to &quot;Loop Prevention&quot;">​</a></h2><p>Failure alerts are designed with safeguards to prevent notification loops:</p><ul><li><p><strong>Notification failures are not reported</strong> -- If the failure alert email itself fails to send, no further notification is generated. This prevents an infinite chain of failure alerts.</p></li><li><p><strong>WordPress default mail transport</strong> -- Failure alerts are sent using the WordPress default mail function with SendGrail hooks <strong>temporarily removed</strong>. This avoids routing the notification through the same SMTP connection that may be experiencing problems, and prevents the notification from being logged, tracked, or processed by SendGrail.</p></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Because failure alerts bypass SendGrail entirely, they rely on whatever mail transport WordPress uses natively (typically PHP <code>mail()</code> or a configured fallback). Ensure your server&#39;s default mail function is operational if you depend on failure alerts.</p></div><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li>Keep failure alerts <strong>enabled</strong> (the default) unless you have an alternative monitoring solution in place.</li><li>Set the <code>notification_email</code> to an address hosted on a <strong>different provider</strong> than your SMTP connections. If your SMTP provider goes down, alerts sent through the same provider would also fail.</li><li>Review failure alerts promptly. Repeated failures for the same connection often indicate expired credentials, blocked accounts, or provider outages.</li></ul>',17)])])}const p=t(o,[["render",n]]);export{f as __pageData,p as default};
